Redactor.add("plugin","inlinestyle",{translations:{en:{style:"Style",marked:"Marked",variable:"Variable",shortcut:"Shortcut"}},init:function(t){this.app=t,this.lang=t.lang,this.toolbar=t.toolbar,this.styles={marked:{title:this.lang.get("marked"),args:"mark"},code:{title:this.lang.get("code"),args:"code"},variable:{title:this.lang.get("variable"),args:"var"},shortcut:{title:this.lang.get("shortcut"),args:"kbd"},sup:{title:this.lang.get("superscript"),args:"sup"},sub:{title:this.lang.get("subscript"),args:"sub"}}},start:function(){var t={};for(var i in this.styles){var s=this.styles[i];t[i]={title:s.title,api:"module.inline.format",args:s.args}}var a=this.toolbar.addButtonAfter("format","inline",{title:this.lang.get("style")});a.setIcon('<i class="re-icon-inline"></i>'),a.setDropdown(t)}});
